    return ResponseEntity.ok(userClient.update(id, user));
  }

  @DeleteMapping(value = "/{id}")
  public ResponseEntity<?> delete(@PathVariable Long id) {
    userClient.delete(id);
    return ResponseEntity.noContent().build();
  }
