    getDateTextColor(affectedDate, dependentDate) {
      let plainColor = this.$vuetify.theme.isDark
        ? "white--text"
        : "black--text";
      if (dependentDate != null) {
        return plainColor;
      }
      let diff = this.getDayDifferenceFromNow(affectedDate);

      if (diff <= 0) {
        return this.$vuetify.theme.isDark
          ? "red--text darken-4"
          : "red--text darken-4";
      } else if (diff <= 3) {
        return this.$vuetify.theme.isDark
          ? "yellow--text lighten-1"
          : "orange--text lighten-2";
      } else {
        return plainColor;
      }
    },
    filterCollectionOverdue() {
      orderService
        .getUsersOrderCollectionOverdue()
        .then(data => {
          this.loading = false;
          this.replaceArray(this.orders, data);
        })
        .catch(err => {
          console.log(err);
          this.loading = false;
          this.$store.commit("setErrorMessage", err.error_description);
        });
    },
    filterReturnOverdue() {
      orderService
        .getUsersOrderReturnOverdue()
        .then(data => {
          this.loading = false;
          this.replaceArray(this.orders, data);
        })
        .catch(err => {
          console.log(err);
          this.loading = false;
          this.$store.commit("setErrorMessage", err.error_description);
        });
    },
    filterAll() {
      this.findAllOrders();
    },
    replaceArray(dest, src) {
      dest.length = 0;
      dest.push(...src);
    },
    getDayDifferenceFromNow(date) {
      let time = Date.parse(date);
      let now = Date.now();
      let diff = time - now;
      return diff / (1000 * 3600 * 24);
    }
  },
  created() {
    this.findAllOrders();
  },
  components: {
    NewOrder,
    MyOrdersHistory,
    FilterOrder
  },
  watch: {
    newAdded() {
      if (this.newAdded) {
        setTimeout(() => (this.newAdded = false), 4000);
        this.findAllOrders();
      }
    }
  }
};
