  }

  @PutMapping(value = "/{id}/return")
  public ResponseEntity<BookOrderDTO> returnBook(@PathVariable Long id)
      throws OrderNotFoundException, GenericException {
    return ResponseEntity.ok(bookOrderService.returnBook(id));
  }
}

